import React from "react";

import JobDesc from "../components/Job/Desc";
import Responsive from "../components/Responsive/";
import BannerPreview from "../components/BannerPreview/";

const bannerTag = (str, campaign, width, height, target) =>
  `/banners/${campaign}_${width}x${height}_${target}/index.html`;
const banners = {
  campaign: "MME",
  target: "Loyalty",
  dim: [
    {
      width: 160,
      height: 600
    },
    {
      width: 300,
      height: 250
    },
    {
      width: 300,
      height: 600
    },
    {
      width: 320,
      height: 480
    },
    {
      width: 300,
      height: 50
    },
    {
      width: 320,
      height: 50
    },
    {
      width: 728,
      height: 90
    }
  ]
};

const Work = ({ data: { workHistory }}) =>
<React.Fragment>
  {
    workHistory.edges.map(({ node }) =>
      <JobDesc {...node} >
        {
          node.project !== "Mortenson Kim" ? null :
          <React.Fragment>
            <h4>Banners</h4>
            <BannerPreview {...banners} />
          </React.Fragment>
        }
      </JobDesc>
    )
  }
</React.Fragment>

export default Work;

export const query = graphql`
  query workHistory {
    workHistory: allWorkJson {
      edges {
        node {
          project
          longName
          intro
          contribution
          links {
            url
            str
          }
        }
      }
    }
  }
`



